1	// claim-office.ts
2	
3	type Customer = {
4	  yearsWithMHPCO: number;
5	};
6	
7	type Item = {
8	  type: string;
9	  material?: string;
10	  cursed?: boolean;
11	  enchantment?: number;
12	};
13	
14	type Damage = {
15	  itemType: string;
16	  amount: number;
17	};
18	
19	type Incident = {
20	  cause: string;
21	  damages: Damage[];
22	};
23	
24	type Step = {
25	  op: string;
26	  items?: Item[];
27	  policy?: number;
28	  incident?: Incident;
29	};
30	
31	type ScenarioInput = {
32	  customer: Customer;
33	  steps: Step[];
34	};
35	
36	type ScenarioOutput = {
37	  results: unknown[];
38	};
39	
40	const PROCESSING_FEE = 5;
41	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
42	const CURSE_SURCHARGE_RATE = 0.5;
43	const HIGH_ENCHANTMENT_THRESHOLD = 5;
44	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
45	const LOYALTY_YEARS_THRESHOLD = 2;
46	const LOYALTY_DISCOUNT_RATE = 0.2;
47	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
48	const COMPONENT_BLOCK_SIZE = 3;
49	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
50	const DEDUCTIBLE = 100;
51	const HIGH_REIMBURSEMENT_ENCHANTMENT_THRESHOLD = 8;
52	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
53	const CAP_MULTIPLIER = 2;
54	
55	const BASE_PREMIUMS: Record<string, number> = {
56	  sword: 100,
57	  amulet: 60,
58	  staff: 80,
59	  potion: 40,
60	  rune: 25,
61	  moonstone: 25,
62	};
63	
64	const INSURANCE_VALUES: Record<string, number> = {
65	  sword: 1000,
66	  rune: 250,
67	};
68	
69	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
70	
71	const isComponentBlock = (type: string, count: number): boolean =>
72	  COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE;
73	
74	const basePremiumFor = (type: string): number => {
75	  const basePremium = BASE_PREMIUMS[type];
76	  if (basePremium === undefined) {
77	    throw new Error(`Unknown item type: ${type}`);
78	  }
79	  return basePremium;
80	};
81	
82	const surchargeFor = (
83	  items: Item[],
84	  applies: (item: Item) => boolean,
85	  rate: number
86	): number =>
87	  items.reduce(
88	    (surcharge, item) =>
89	      applies(item) ? surcharge + basePremiumFor(item.type) * rate : surcharge,
90	    0
91	  );
92	
93	const isCursed = (item: Item): boolean => item.cursed === true;
94	
95	const isHighlyEnchanted = (item: Item): boolean =>
96	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
97	
98	const curseSurchargeFor = (items: Item[]): number =>
99	  surchargeFor(items, isCursed, CURSE_SURCHARGE_RATE);
100	
101	const enchantmentSurchargeFor = (items: Item[]): number =>
102	  surchargeFor(items, isHighlyEnchanted, HIGH_ENCHANTMENT_SURCHARGE_RATE);
103	
104	const groupBasePremium = (type: string, count: number): number =>
105	  isComponentBlock(type, count)
106	    ? COMPONENT_BLOCK_BASE_PREMIUM
107	    : count * basePremiumFor(type);
108	
109	const policyBaseFor = (items: Item[]): number => {
110	  const countsByType = new Map<string, number>();
111	  for (const item of items) {
112	    countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
113	  }
114	
115	  let policyBase = 0;
116	  for (const [type, count] of countsByType) {
117	    policyBase += groupBasePremium(type, count);
118	  }
119	  return policyBase;
120	};
121	
122	const qualifiesForLoyaltyDiscount = (customer: Customer): boolean =>
123	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
124	
125	const quotePremium = (
126	  items: Item[],
127	  customer: Customer,
128	  isFollowUp: boolean
129	): number => {
130	  const policyBase = policyBaseFor(items);
131	  const itemSurcharges =
132	    curseSurchargeFor(items) + enchantmentSurchargeFor(items);
133	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
134	  const loyaltyDiscount = qualifiesForLoyaltyDiscount(customer)
135	    ? policyBase * LOYALTY_DISCOUNT_RATE
136	    : 0;
137	  const followUpDiscount = isFollowUp
138	    ? policyBase * FOLLOW_UP_DISCOUNT_RATE
139	    : 0;
140	  return Math.ceil(
141	    policyBase +
142	      itemSurcharges +
143	      firstInsuranceSurcharge -
144	      loyaltyDiscount -
145	      followUpDiscount +
146	      PROCESSING_FEE
147	  );
148	};
149	
150	const isFollowUpQuote = (stepIndex: number): boolean => stepIndex > 0;
151	
152	const insuranceSumFor = (items: Item[]): number =>
153	  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
154	
155	const processClaim = (step: Step, steps: Step[]): unknown => {
156	  const policyItems = steps[step.policy!].items ?? [];
157	  const payoutCap = insuranceSumFor(policyItems) * CAP_MULTIPLIER;
158	  const damage = step.incident!.damages[0];
159	  const damagedItem = policyItems.find((item) => item.type === damage.itemType);
160	  const reimbursementRate =
161	    (damagedItem?.enchantment ?? 0) >= HIGH_REIMBURSEMENT_ENCHANTMENT_THRESHOLD
162	      ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
163	      : 1;
164	  const payout = damage.amount * reimbursementRate - DEDUCTIBLE;
165	  return { payout, remainingCap: payoutCap - payout };
166	};
167	
168	export const processScenario = (input: ScenarioInput): ScenarioOutput => {
169	  const results = input.steps.map((step, index) =>
170	    step.op === "claim"
171	      ? processClaim(step, input.steps)
172	      : {
173	          premium: quotePremium(
174	            step.items ?? [],
175	            input.customer,
176	            isFollowUpQuote(index)
177	          ),
178	        }
179	  );
180	  return { results };
181	};
